async def random_card(update: Update, context: ContextTypes.DEFAULT_TYPE):
    card_num = random.randint(1, 78)
    if update.message:
        chat_id = update.message.chat_id
        reply_id = update.message.message_id
        await send_card(update, chat_id, card_num, reply_id)
    elif update.callback_query:
        chat_id = update.callback_query.message.chat_id
        reply_id = update.callback_query.message.message_id
        await send_card(update, chat_id, card_num, reply_id)
        await update.callback_query.answer()

async def handle_message(update: Update, context: ContextTypes.DEFAULT_TYPE):
    """Обработка чисел в комментариях и личке"""
    # Проверяем, есть ли текст в сообщении
    if not update.message or not update.message.text:
        return  # игнорируем сообщения без текста
    
    text = update.message.text.strip().lower()
    chat_id = update.message.chat_id
    reply_id = update.message.message_id
    
    # Проверяем на "рандом"
    if text in ["рандом", "random", "/random"]:
        card_num = random.randint(1, 78)
        await send_card(update, chat_id, card_num, reply_id)
        return
    
    # Проверяем, является ли сообщение числом от 1 до 78
    if text.isdigit():
        num = int(text)
        if 1 <= num <= 78:
            await send_card(update, chat_id, num, reply_id)
        else:
            await update.message.reply_text(
                "Пожалуйста, введите число от 1 до 78. Или напишите «рандом» для случайной карты.",
                reply_to_message_id=reply_id
            )
    # Если не число и не "рандом" — ничего не делаем (не спамим)

async def button_callback(update: Update, context: ContextTypes.DEFAULT_TYPE):
    query = update.callback_query
    await query.answer()
    if query.data == "random":
        card_num = random.randint(1, 78)
        await send_card(update, query.message.chat_id, card_num, query.message.message_id)
    elif query.data == "position":
        await position_command(update, context)
    elif query.data == "help":
        await help_command(update, context)

# ========== ЗАПУСК ==========
def main():
    app = Application.builder().token(TOKEN).build()
    
    app.add_handler(CommandHandler("start", start))
    app.add_handler(CommandHandler("help", help_command))
    app.add_handler(CommandHandler("random", random_card))
    app.add_handler(CommandHandler("position", position_command))
    app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, handle_message))
    app.add_handler(CallbackQueryHandler(button_callback))
    
    print("✨ Бот Оракул Таро запущен!")
    print("Работает в личных сообщениях и каналах.")
    app.run_polling()

if __name__ == "__main__":
    main()
